import './index.css';

import {
  useState
} from 'react';

import {
  addMarks
} from '../../services/marksService';

function AddMarksPage() {

  const [formData, setFormData] =
    useState({

      student_id: '',
      subject_id: '',
      assessment_id: '',
      marks_obtained: ''

    });

  const handleChange =
    (e) => {

    setFormData({

      ...formData,

      [e.target.name]:
      e.target.value

    });

  };

  const handleSubmit =
    async (e) => {

    e.preventDefault();

    try {

      await addMarks(formData);

      alert(
        'Marks Added Successfully'
      );

      setFormData({

        student_id: '',
        subject_id: '',
        assessment_id: '',
        marks_obtained: ''

      });

    } catch (error) {

      console.log(error);

      alert(
        error.response?.data?.message
      );

    }

  };

  return (

    <div className="marks-page">

      <h1>
        Add Student Marks
      </h1>

      <form
        className="marks-form"
        onSubmit={handleSubmit}
      >

        <input
          type="number"
          name="student_id"
          placeholder="Student ID"
          value={formData.student_id}
          onChange={handleChange}
          required
        />

        <input
          type="number"
          name="subject_id"
          placeholder="Subject ID"
          value={formData.subject_id}
          onChange={handleChange}
          required
        />

        <input
          type="number"
          name="assessment_id"
          placeholder="Assessment ID"
          value={formData.assessment_id}
          onChange={handleChange}
          required
        />

        <input
          type="number"
          name="marks_obtained"
          placeholder="Marks Obtained"
          value={formData.marks_obtained}
          onChange={handleChange}
          required
        />

        <button type="submit">

          Add Marks

        </button>

      </form>

    </div>

  );

}

export default AddMarksPage;
